 		p.Command = argsIn[argsLenAtDash:]
 	} else if len(argsIn) > 1 || (len(argsIn) > 0 && len(p.FilenameOptions.Filenames) != 0) {
 		return cmdutil.UsageErrorf(cmd, "exec [POD] [COMMAND] is not supported anymore. Use exec [POD] -- [COMMAND] instead")', 'advice': '变更符合项目架构设计，无需修改。代码注释清晰解释了变更目的和前提条件(pflag的保证)。', 'confidence': 0.9, 'relevance': 0.7, 'severity': 'Medium'}, {'type': 'Design', 'conclusion': '修复exec命令参数解析逻辑，增强边界检查', 'description': '代码变更修复了kubectl exec命令的参数解析逻辑。原逻辑仅检查argsLenAtDash > -1，这允许在资源名称和分隔符(--)之间存在额外参数，导致意外行为。新逻辑严格限制argsLenAtDash只能为0或1，确保分隔符前只有一个参数（资源名称）。同时添加了相应的测试用例验证边界情况。', 'evidence': 'if argsLenAtDash == 0 || argsLenAtDash == 1 {
